import React from "react";
import "./InternshipCard.css";

const InternshipCard = ({ data, onClick }) => {
  return (
    <div className="internship-card" onClick={onClick}>
      <h3>{data.title}</h3>
      <p><strong>Company:</strong> {data.company}</p>
      <p><strong>Location:</strong> {data.location}</p>
      <p><strong>Stipend:</strong> {data.stipend}</p>
      <span className={`status ${data.applied ? "applied" : "not-applied"}`}>
        {data.applied ? "Applied" : "Not Applied"}
      </span>
    </div>
  );
};

export default InternshipCard;
